1	import readline from 'node:readline'
2	
3	import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
4	
5	import * as JsonRpc from './json-rpc'
6	
7	export interface Handler {
8	  onGenerate(options: GeneratorOptions): Promise<any>
9	  onManifest?(config: GeneratorConfig): GeneratorManifest | Promise<GeneratorManifest>
10	}
11	
12	export function generatorHandler(handler: Handler): void {
13	  const stdinInterface = readline.createInterface({
14	    input: process.stdin,
15	    crlfDelay: Infinity,
16	  })
17	
18	  stdinInterface.on('line', async (line: string) => {
19	    const json = JSON.parse(line)
20	
21	    if (json.method === 'generate' && json.params) {
22	      try {
23	        const result = await handler.onGenerate(json.params)
24	        respond({
25	          jsonrpc: '2.0',
26	          result: result,
27	          id: json.id,
28	        })
29	      } catch (_e) {
30	        const e = _e as Error
31	        respond({
32	          jsonrpc: '2.0',
33	          error: {
34	            code: -32000,
35	            message: e.message,
36	            data: {
37	              stack: e.stack,
38	            },
39	          },
40	          id: json.id,
41	        })
42	      }
43	    }
44	
45	    if (json.method === 'getManifest') {
46	      if (handler.onManifest) {
47	        try {
48	          const manifest = await handler.onManifest(json.params)
49	          respond({
50	            jsonrpc: '2.0',
51	            result: {
52	              manifest,
53	            },
54	            id: json.id,
55	          })
56	        } catch (_e) {
57	          const e = _e as Error
58	          respond({
59	            jsonrpc: '2.0',
60	            error: {
61	              code: -32000,
62	              message: e.message,
63	              data: {
64	                stack: e.stack,
65	              },
66	            },
67	            id: json.id,
68	          })
69	        }
70	      } else {
71	        respond({
72	          jsonrpc: '2.0',
73	          result: {
74	            manifest: null,
75	          },
76	          id: json.id,
77	        })
78	      }
79	    }
80	  })
81	
82	  process.stdin.resume()
83	}
84	
85	function respond(response: JsonRpc.Response): void {
86	  process.stderr.write(JSON.stringify(response) + '\n')
87	}
