/**
 * Maps a Prisma scalar type name to the corresponding TypeScript type string.
 */
export function mapScalarType(prismaType: string): string {
  switch (prismaType) {
    case 'String':
      return 'string'
    case 'Int':
    case 'Float':
      return 'number'
    case 'Boolean':
      return 'boolean'
    case 'DateTime':
      return 'Date'
    case 'BigInt':
      return 'bigint'
    case 'Decimal':
      return 'string'
    case 'Bytes':
      return 'Buffer'
    case 'Json':
      return 'unknown'
    default:
      // Enum or relation model names pass through as-is.
      return prismaType
  }
}

/**
 * Returns the TypeScript type for a DMMF field, including list and optional
 * modifiers.
 */
export function getFieldTsType(field: DMMF.Field): string {
  const base = field.kind === 'scalar' || field.kind === 'enum' ? mapScalarType(field.type) : field.type

  const withList = field.isList ? `${base}[]` : base
  return field.isRequired ? withList : `${withList} | null`
}

/**
 * Generates a TypeScript interface declaration for a Prisma model.
 */
export function generateModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => {
      const optional = !f.isRequired ? '?' : ''
      const tsType = getFieldTsType(f)
      return `  ${f.name}${optional}: ${tsType}`
    })
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}`
}

/**
 * Builds the `WhereUnique` inline type for a model, derived from fields that
 * carry `@id` or `@unique`.
 */
export function buildWhereUnique(model: DMMF.Model): string {
  const uniqueFields = model.fields.filter((f) => f.isId || f.isUnique)

  if (uniqueFields.length === 0) {
    return 'Record<string, unknown>'
  }

  const members = uniqueFields.map((f) => `${f.name}?: ${mapScalarType(f.type)}`).join('; ')
  return `{ ${members} }`
}

/**
 * Generates the readonly model property block that is inlined into the
 * `RestApiClient` class.  Each property exposes `findMany`, `findUnique`,
 * `create`, `update`, and `delete` methods typed to the model.
 */
export function generateModelClientProperty(model: DMMF.Model): string {
  const name = model.name
  const camelName = name.charAt(0).toLowerCase() + name.slice(1)
  const whereUnique = buildWhereUnique(model)

  // Scalar fields only — relations are not sent over a REST call.
  const scalarFields = model.fields.filter((f) => f.kind === 'scalar')

  // For create, omit auto-generated fields (id with default value).
  const createOmitFields = scalarFields.filter((f) => f.isId && f.hasDefaultValue).map((f) => `'${f.name}'`)

  const createDataType =
    createOmitFields.length > 0 ? `Omit<${name}, ${createOmitFields.join(' | ')}>` : `Omit<${name}, never>`

  return `  readonly ${camelName} = {
    findMany: (params?: { skip?: number; take?: number }): Promise<${name}[]> =>
      this.#request('GET', '/${camelName}', params),
    findUnique: (where: ${whereUnique}): Promise<${name} | null> =>
      this.#request('GET', \`/${camelName}/\${this.#encodeWhere(where)}\`),
    create: (data: ${createDataType}): Promise<${name}> =>
      this.#request('POST', '/${camelName}', data),
    update: (where: ${whereUnique}, data: Partial<${name}>): Promise<${name}> =>
      this.#request('PATCH', \`/${camelName}/\${this.#encodeWhere(where)}\`, data),
    delete: (where: ${whereUnique}): Promise<${name}> =>
      this.#request('DELETE', \`/${camelName}/\${this.#encodeWhere(where)}\`),
  } as const`
}

/**
 * Generates the complete `rest-client.ts` file contents for the given DMMF
 * document.
 */
export function generateRestClient(dmmf: DMMF.Document): string {
  const models = dmmf.datamodel.models

  const interfaces = models.map(generateModelInterface).join('\n\n')
  const properties = models.map(generateModelClientProperty).join('\n\n')

  return `// This file was auto-generated by @prisma/generator-rest-client. Do not edit.

${interfaces}

export class RestApiClient {
  #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl.replace(/\\/$/, '')
  }

${properties}

  #encodeWhere(where: Record<string, unknown>): string {
    const [key, value] = Object.entries(where)[0] ?? []
    return key !== undefined ? \`\${encodeURIComponent(key)}/\${encodeURIComponent(String(value))}\` : ''
  }

  async #request<T>(method: string, path: string, body?: unknown): Promise<T> {
    const url = new URL(\`\${this.#baseUrl}\${path}\`)

    if ((method === 'GET' || method === 'DELETE') && body !== null && body !== undefined) {
      for (const [k, v] of Object.entries(body as Record<string, unknown>)) {
        if (v !== undefined) {
          url.searchParams.set(k, String(v))
        }
      }
    }

    const hasBody = method !== 'GET' && method !== 'DELETE' && body !== undefined
    const response = await fetch(url.toString(), {
      method,
      headers: hasBody ? { 'Content-Type': 'application/json' } : undefined,
      body: hasBody ? JSON.stringify(body) : undefined,
    })

    if (!response.ok) {
      throw new Error(\`REST API error \${response.status}: \${await response.text()}\`)
    }

    return response.json() as Promise<T>
  }
}
`
}

