import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './template'

/**
 * Runs the REST client generator.
 *
 * Reads the output directory from the generator configuration, generates the
 * typed client source, and writes `rest-client.ts` into that directory.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value

  if (!outputDir) {
    throw new Error('@prisma/generator-rest-client: "output" is required in the generator block')
  }

  const resolvedOutput = path.isAbsolute(outputDir) ? outputDir : path.resolve(process.cwd(), outputDir)

  await fs.mkdir(resolvedOutput, { recursive: true })

  const clientSource = generateRestClient(options.dmmf)

  await fs.writeFile(path.join(resolvedOutput, 'rest-client.ts'), clientSource, 'utf-8')
}

